{"code": "import json

# Get the list of symbols
financially_troubled_companies = locals()['var_functions.query_db:2']
symbols = [company['Symbol'] for company in financially_troubled_companies]

print('Preparing to check 2008 data for these symbols:')
for i, symbol in enumerate(symbols, 1):
    print(f"{i}. {symbol}")
print(f"Total: {len(symbols)} symbols")

# Create individual queries for each symbol
queries = {}
for symbol in symbols:
    query = f"SELECT \"{symbol}\" as Symbol, COUNT(*) as record_count, AVG(Volume) as avg_volume FROM {symbol} WHERE SUBSTRING(CAST(Date AS VARCHAR), 1, 4) = '2008'"
    queries[symbol] = query

print(f'\nGenerated {len(queries)} queries')

print('__RESULT__:')
print(json.dumps({
    'symbols': symbols,
    'count': len(symbols)
}))"}

