{"code": "import json

# Get the company information
companies = locals()['var_functions.query_db:2']

# Create a results dictionary to store all results
all_results = {}

# Market category mapping
market_cat_map = {'Q': 'NASDAQ Global Select Market', 'G': 'NASDAQ Global Market', 'S': 'NASDAQ Capital Market'}

# Financial status mapping  
status_map = {
    'D': 'Deficient',
    'E': 'Delinquent', 
    'G': 'Deficient and Bankrupt',
    'H': 'Deficient and Delinquent',
    'J': 'Delinquent and Bankrupt',
    'K': 'Deficient, Delinquent, and Bankrupt'
}

# Process companies and build query list
companies_info = {}
for company in companies:
    symbol = company['Symbol']
    desc = company['Company Description']

    # Clean up company name
    if '.' in desc:
        company_name = desc.split('.')[0].strip()
    else:
        company_name = desc[:80].strip()
        if len(desc) > 80:
            company_name += '...'

    companies_info[symbol] = {
        'name': company_name,
        'market': market_cat_map.get(company['Market Category'], company['Market Category']),
        'status': status_map.get(company['Financial Status'], company['Financial Status'])
    }

print('Loaded info for', len(companies_info), 'companies')
print('Symbols to check:', list(companies_info.keys()))

# Save company info for later use
output_data = {
    'companies_info': companies_info,
    'symbols': list(companies_info.keys())
}

print('__RESULT__:')
print(json.dumps(output_data))"}

